-- Step 1: ลบ contracts ที่เป็น ff365 (ซ้ำกับ Fastfone365)
DELETE FROM contracts WHERE section = 'ff365';

-- Step 2: ลบ installments ที่เป็น ff365
DELETE FROM installments WHERE section = 'ff365';

-- Step 3: ลบ contracts ที่เป็น boonphone (ซ้ำกับ Boonphone ที่มี 4,212 rows)
-- แต่ก่อนต้องตรวจสอบว่า boonphone มีข้อมูลใหม่กว่า Boonphone ไหม
SELECT section, COUNT(*) as cnt FROM contracts GROUP BY section;

